  var byD=[],idx={};cal.forEach(function(j){var dia=fmtDia(j.inicio)||"A definir";if(idx[dia]==null){idx[dia]=byD.length;byD.push({dia:dia,jogos:[]});}byD[idx[dia]].jogos.push(j);});
