 var row=function(med,cls,lab,slot,pts){var sx=lpSelDe(LP_PICK[slot]);return '<div class="lprow"><span class="lpmed '+cls+'">'+med+'</span><span class="lplab">'+lab+'</span><div class="acf'+(sx?' has':'')+'"><span class="acico" id="ico-'+slot+'">'+(sx?lpFlag(sx.iso):'')+'</span><input class="acin" id="ac-'+slot+'" autocomplete="off" placeholder="selecione" value="'+(sx?esc(sx.pt):'')+'"'+(LP_LOCK?' disabled':'')+'><div class="acdd" id="dd-'+slot+'"></div>'+(LP_LOCK?'':'<button class="acx" onclick="lpClear(&#39;'+slot+'&#39;)" title="Limpar">&times;</button>')+'</div><span class="lppts">'+pts+'</span></div>';};
