 var info=LP_LOCK?'<p class="lpsub">&#128274; Travado (fim da Rodada 2). Veja o que voce cravou.</p>':'<p class="lpsub">Crave uma vez &middot; trava no fim da R2 &middot; vale ate 525 pts</p>';
