function rrow(a,b){return '<div class="rrow"><span>'+a+'</span><b>'+b+'</b></div>';}var REGRAS_CFG=null;function rgBolao(c){var p=(c&&c.pontos)||{};return '<div class="rrow rhead"><span></span><b>PONTOS &amp; TOKENS</b></div>'+rrow('Placar exato',p.exato!=null?p.exato:10)+rrow('Vencedor + saldo de gols',p.vencedor_saldo!=null?p.vencedor_saldo:7)+rrow('Vencedor certo',p.vencedor!=null?p.vencedor:5)+rrow('Acertou os gols de um time',p.gol_time!=null?p.gol_time:1);}function rgMata(c){var m=(c&&c.mata)||{};return '<div class="rrow rhead"><span></span><b>MULTIPLICADOR</b></div>'+rrow('Rodada de 32','×'+(m.r32!=null?m.r32:1))+rrow('Oitavas','×'+(m.oitavas!=null?m.oitavas:2))+rrow('Quartas','×'+(m.quartas!=null?m.quartas:4))+rrow('Semifinal','×'+(m.semi!=null?m.semi:8))+rrow('Disputa de 3º','×'+(m.terceiro!=null?m.terceiro:5))+rrow('Final','×'+(m.final!=null?m.final:10));}function rgLongo(c){var l=(c&&c.longo)||{};var art=Array.isArray(l.artilheiro)?l.artilheiro[0]:l.artilheiro;return '<div class="rrow rhead"><span></span><b>PONTOS</b></div>'+rrow('Campeão',l.campeao!=null?l.campeao:200)+rrow('Vice-campeão',l.vice!=null?l.vice:150)+rrow('3º lugar',l.terceiro!=null?l.terceiro:100)+rrow('4º lugar',l.quarto!=null?l.quarto:75)+rrow('Artilheiro',art!=null?art:100);}function rgArena(c){var a=(c&&c.arena)||{};var pv=(a.pts&&a.pts[0]!=null)?a.pts[0]:50;return '<div class="rrow rhead"><span></span><b>PONTOS</b></div>'+rrow('Vitória (cada)',pv)+rrow('Derrota — experiência por jogar',a.pts_derrota!=null?a.pts_derrota:10);}function ensureRegras(){if(REGRAS_CFG)return Promise.resolve(REGRAS_CFG);return fetch(BASE+"/jogar/regras",{headers:H()}).then(function(r){return r.json();}).then(function(d){REGRAS_CFG=d||{};return REGRAS_CFG;}).catch(function(){REGRAS_CFG={};return REGRAS_CFG;});}function loadRegras(){ensureRegras().then(function(c){var set=function(id,html){var el=document.getElementById(id);if(el)el.innerHTML=html;};set('rg-bolao',rgBolao(c));set('rg-mata',rgMata(c));set('rg-longo',rgLongo(c));set('rg-arena',rgArena(c));});}function regrasRank(){ensureRegras().then(function(c){var card=function(t,body){return '<div class="card" style="margin-bottom:10px"><h3>'+t+'</h3>'+body+'</div>';};var bBolao=card('⚽ Bolão — fase de grupos',rgBolao(c));var bMata=card('🏆 Mata-mata',rgMata(c));var bLongo=card('🥇 Longo prazo',rgLongo(c));var st=(c.arena&&c.arena.stake!=null)?c.arena.stake:50;var rk=(c.arena&&c.arena.rake!=null)?c.arena.rake:10;var bArena=card('⚔️ Arena (PvP)','<p class="lpsub" style="margin:0 0 6px">Aposta '+st+' tokens, vencedor leva '+(st*2-rk)+'.</p>'+rgArena(c));var bPote='<div class="card"><h3>💰 Pote de Ouro</h3><p class="muted" style="margin:0">Geral = Bolão + Arena + Mata-mata + Longo prazo. Os 3 primeiros dividem 50/30/20.</p></div>';var hd=function(t){return '<div class="lphd"><span class="lphdic">📋</span><b>'+t+'</b></div>';};var html;if(RANKTIPO==='bolao')html=hd('Regras do Bolão')+bBolao+bMata+bLongo;else if(RANKTIPO==='arena')html=hd('Regras da Arena')+bArena;else html=hd('Todas as regras')+bBolao+bMata+bLongo+bArena+bPote;modal(html,'');});}
