function fecharPac(){var ov=document.getElementById("pacov");if(ov){ov.classList.remove("on");setTimeout(function(){if(ov.parentNode)ov.parentNode.removeChild(ov);},220);}}
function abrirPacote(){fetch(BASE+"/jogar/pacote/abrir",{method:"POST",headers:H()}).then(function(r){return r.json();}).then(function(d){if(!d||!d.ok){if(d&&d.jaAbriu){toast("Voce ja abriu seu pacote!");}else if(d&&d.semSaldo){toast("Saldo insuficiente: o pacote custa 300 tokens.");}else{toast("Erro ao abrir o pacote.");}return;}_UNCARDS=d.cartas||[];var ov=document.getElementById("unbox");var e=document.getElementById("uenv");e.src=BASE+"/fig/pack/inicial";e.style.display="";e.style.opacity="1";e.style.animation="upackfloat 3.4s ease-in-out infinite";var fl=document.getElementById("uflash");if(fl)fl.style.opacity="0";var ub=document.getElementById("uburst");if(ub){ub.style.display="";ub.style.opacity="1";}var sps=document.querySelectorAll("#unbox .usp");for(var i=0;i<sps.length;i++){sps[i].style.display="";}document.getElementById("utap").style.display="";document.getElementById("utap").style.opacity="0.9";document.getElementById("ucards").innerHTML="";var uh=document.getElementById("uhead");uh.textContent="";uh.style.opacity="0";document.getElementById("ubtnfim").style.opacity="0";ov.classList.add("on");}).catch(function(){toast("Erro de conexao.");});}
function rasgarPacote(){var env=document.getElementById("uenv"),tap=document.getElementById("utap"),box=document.getElementById("ucards"),head=document.getElementById("uhead"),fim=document.getElementById("ubtnfim"),fl=document.getElementById("uflash"),ub=document.getElementById("uburst");var h="";for(var i=0;i<_UNCARDS.length;i++){var c=_UNCARDS[i];h+='<div class="ucard"><img src="'+BASE+'/fig/'+c.figurinha+'" alt=""></div>';}env.style.animation="none";if(window.gsap){gsap.to(tap,{duration:0.2,opacity:0});if(fl){gsap.fromTo(fl,{opacity:0},{opacity:1,duration:0.16,yoyo:true,repeat:1});}gsap.to(env,{duration:0.5,scale:1.55,opacity:0,y:-30,rotation:8,ease:"power2.in"});if(ub){gsap.to(ub,{opacity:0,duration:0.45});}gsap.to("#unbox .usp",{opacity:0,duration:0.3});}setTimeout(function(){env.style.display="none";tap.style.display="none";if(ub)ub.style.display="none";var sps=document.querySelectorAll("#unbox .usp");for(var k=0;k<sps.length;k++)sps[k].style.display="none";box.innerHTML=h;head.textContent="SEU TIME CHEGOU!";var cs=box.querySelectorAll(".ucard");if(window.gsap){gsap.to(head,{opacity:1,duration:0.4});gsap.fromTo(cs,{opacity:0,scale:0.4,y:30,rotateY:90},{opacity:1,scale:1,y:0,rotateY:0,duration:0.5,stagger:0.06,ease:"back.out(1.6)"});gsap.to(fim,{opacity:1,duration:0.4,delay:1});}else{for(var k2=0;k2<cs.length;k2++)cs[k2].style.opacity=1;head.style.opacity=1;fim.style.opacity=1;}},520);}
function fecharUnbox(){var ov=document.getElementById("unbox");if(ov)ov.classList.remove("on");renderHomeField();nav("time");}
